import React, { useState } from "react";
import "./package.css";
import bookImage from "../Assets/book.jpg";
import glamImage from "../Assets/glam.jpg";
import tentImage from "../Assets/tent3.jpg";
import img1 from "../Assets/glam.jpg";
import img2 from "../Assets/img1.jpg";
import img3 from "../Assets/img5.jpg";
import img4 from "../Assets/tent3.jpg";
import img5 from "../Assets/tent2.jpg";
import img6 from "../Assets/tent5.jpg";
import img7 from "../Assets/tent6.avif";

// Import components
import Book from "./book";
import Gallery from "./gallary";

const mixedGallery = [
  { image: img1, stayType: "Glam Stay" },
  { image: img2, stayType: "Tent Stay" },
  { image: img3, stayType: "Glam Stay" },
  { image: img4, stayType: "Tent Stay" },
  { image: img5, stayType: "Tent Stay" },
  { image: img6, stayType: "Tent Stay" },
  { image: img7, stayType: "Tent Stay" },
];

function App() {
  const [selectedStay, setSelectedStay] = useState(null);
  const [showGallery, setShowGallery] = useState(false);

  const handleGalleryClick = (stayType) => {
    setSelectedStay(stayType);
    setShowGallery(true);
  };

  return (
    <div className="app">
      <h1 className="heading">Our Packages</h1>
      <div className="card-container horizontal">
        <div className="card">
          <div className="card-image-container">
            <img src={tentImage} alt="Tent Stay" className="card-image" />
          </div>
          <div className="card-content">
            <h2 className="card-title">Tent Stay</h2>
            <p className="card-price">Starting From ₹2499 Per Person</p>
            <button className="add-to-cart" onClick={() => handleGalleryClick("Tent Stay")}>
              BOOK NOW
            </button>
          </div>
        </div>
        <div className="card">
          <div className="card-image-container">
            <img src={glamImage} alt="Glam Stay" className="card-image" />
          </div>
          <div className="card-content">
            <h2 className="card-title">Glam Stay</h2>
            <p className="card-price">Starting From ₹3499 Per Person</p>
            <button className="add-to-cart" onClick={() => handleGalleryClick("Glam Stay")}>
              BOOK NOW
            </button>
          </div>
        </div>
      </div>

      {selectedStay && <Book stayType={selectedStay} />}
      {showGallery && <Gallery galleryItems={mixedGallery} />}
    </div>
  );
}

export default App;
